// src/App.jsx
// Root component — wires the flipbook, reference panel, admin, and navigation.

import { useState, useRef, useEffect, useCallback } from "react";
import HTMLFlipBook from "react-pageflip";

import { DEFAULT_PAGES } from "./data/pages.js";
import BookPage        from "./components/BookPage.jsx";
import ReferencePanel  from "./components/ReferencePanel.jsx";
import NavBtn          from "./components/NavBtn.jsx";
import KeyboardNav     from "./components/KeyboardNav.jsx";
import LoginScreen     from "./components/LoginScreen.jsx";
import AdminPanel      from "./components/AdminPanel.jsx";

export default function App() {
  const [pages,       setPages]       = useState(DEFAULT_PAGES);
  const [currentPage, setCurrentPage] = useState(0);
  const [showRef,     setShowRef]     = useState(false);   // reference panel visibility
  const [showLogin,   setShowLogin]   = useState(false);
  const [showAdmin,   setShowAdmin]   = useState(false);
  const [isLoggedIn,  setIsLoggedIn]  = useState(false);
  const [bookDim,     setBookDim]     = useState({ w: 340, h: 440 });
  const flipRef = useRef(null);

  /* responsive sizing */
  useEffect(() => {
    const update = () => {
      const vw = window.innerWidth;
      const vh = window.innerHeight;
      const w  = Math.min(320, vw * 0.43);
      const h  = Math.min(440, vh * 0.62);
      setBookDim({ w: Math.floor(w), h: Math.floor(h) });
    };
    update();
    window.addEventListener("resize", update);
    return () => window.removeEventListener("resize", update);
  }, []);

  const onPage = useCallback((e) => {
    setCurrentPage(e.data);
    setShowRef(false); // close ref panel on page turn
  }, []);

  const prev = () => flipRef.current?.pageFlip().flipPrev("bottom");
  const next = () => flipRef.current?.pageFlip().flipNext("bottom");

  const totalPages  = pages.length;
  const progress    = totalPages > 1 ? currentPage / (totalPages - 1) : 0;
  const activePage  = pages[currentPage];

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg,#0f0c29 0%,#302b63 50%,#24243e 100%)",
      display: "flex", flexDirection: "column", alignItems: "center",
      justifyContent: "center", padding: "20px 16px",
      fontFamily: "'Nunito',sans-serif",
      position: "relative", overflow: "hidden",
    }}>
      {/* Google Fonts */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bubblegum+Sans&family=Nunito:wght@400;600;700;800;900&display=swap');
        * { box-sizing: border-box; }
        .flip-book .stf__parent { border-radius: 4px; }
        @keyframes float {
          0%,100% { transform: translateY(0px) rotate(0deg); }
          50%      { transform: translateY(-12px) rotate(5deg); }
        }
        @keyframes twinkle {
          0%,100% { opacity: 0.4; transform: scale(1); }
          50%      { opacity: 1;   transform: scale(1.3); }
        }
        @keyframes pulse-btn {
          0%,100% { box-shadow: 0 0 0 0 rgba(167,139,250,0.4); }
          50%      { box-shadow: 0 0 0 12px rgba(167,139,250,0); }
        }
      `}</style>

      {/* floating background stars */}
      {["⭐","🌟","✨","💫","🌙","⭐","✨"].map((e, i) => (
        <div key={i} style={{
          position: "fixed",
          top: `${8 + i * 12}%`,
          left: i % 2 === 0 ? `${3 + i * 4}%` : `${80 + i * 2}%`,
          fontSize: 18 + i * 4,
          animation: `twinkle ${2 + i * 0.4}s ease-in-out infinite`,
          animationDelay: `${i * 0.3}s`,
          pointerEvents: "none", opacity: 0.4,
        }}>{e}</div>
      ))}

      {/* title */}
      <div style={{
        color: "#fff", fontFamily: "'Bubblegum Sans',cursive",
        fontSize: "clamp(22px,5vw,36px)", fontWeight: 400,
        marginBottom: 16, textShadow: "0 2px 20px rgba(167,139,250,0.6)",
        letterSpacing: "0.04em", textAlign: "center",
        animation: "float 4s ease-in-out infinite",
      }}>
        📖 Magic Story Book
      </div>

      {/* progress bar */}
      <div style={{
        width: bookDim.w * 2 + 12, maxWidth: "96vw",
        height: 6, background: "rgba(255,255,255,0.1)",
        borderRadius: 3, marginBottom: 12, overflow: "hidden",
      }}>
        <div style={{
          width: `${progress * 100}%`, height: "100%",
          background: "linear-gradient(90deg,#7c3aed,#06b6d4)",
          borderRadius: 3, transition: "width 0.4s ease",
        }} />
      </div>

      {/* THE BOOK */}
      <div style={{ filter: "drop-shadow(0 20px 40px rgba(0,0,0,0.5))", position: "relative" }}>
        <HTMLFlipBook
          ref={flipRef}
          width={bookDim.w} height={bookDim.h}
          size="fixed"
          minWidth={200} minHeight={280}
          maxWidth={500} maxHeight={600}
          drawShadow flippingTime={700}
          usePortrait={false} startZIndex={10}
          autoSize={false} mobileScrollSupport={false}
          onFlip={onPage}
          className="flip-book"
          style={{ margin: "0 auto" }}
        >
          {pages.map((p, i) => (
            <div key={p.id} style={{ width: bookDim.w, height: bookDim.h, background: "#fff", overflow: "hidden" }}>
              <BookPage
                page={p}
                pageNum={i + 1}
                total={totalPages}
                onShowRef={p.reference ? () => setShowRef(true) : null}
              />
            </div>
          ))}
        </HTMLFlipBook>
      </div>

      {/* page label */}
      <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 13, marginTop: 10, fontWeight: 600 }}>
        Page {currentPage + 1} of {totalPages}
      </div>

      {/* navigation */}
      <div style={{ display: "flex", gap: 16, marginTop: 14, alignItems: "center" }}>
        <NavBtn onClick={prev} label="◀ Prev" disabled={currentPage === 0} />
        <div style={{
          width: 48, height: 48, borderRadius: "50%",
          background: "linear-gradient(135deg,#7c3aed,#06b6d4)",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 22, cursor: "default",
          boxShadow: "0 0 0 4px rgba(124,58,237,0.3)",
        }}>📖</div>
        <NavBtn onClick={next} label="Next ▶" disabled={currentPage >= totalPages - 1} />
      </div>

      {/* keyboard hint */}
      <div style={{ color: "rgba(255,255,255,0.25)", fontSize: 11, marginTop: 8 }}>
        ← → arrow keys or click the page edges
      </div>

      {/* reference hint badge */}
      {activePage?.reference && (
        <div style={{
          marginTop: 10,
          background: "rgba(139,92,246,0.2)",
          border: "1px solid rgba(139,92,246,0.4)",
          borderRadius: 20, padding: "6px 16px",
          color: "#c4b5fd", fontSize: 13, fontWeight: 700,
          cursor: "pointer",
          display: "flex", alignItems: "center", gap: 6,
        }} onClick={() => setShowRef(true)}>
          🔍 Learn about: <span style={{ color: "#e0e7ff" }}>{activePage.reference.title}</span>
        </div>
      )}

      {/* admin button */}
      <button
        onClick={() => isLoggedIn ? setShowAdmin(true) : setShowLogin(true)}
        style={{
          position: "fixed", bottom: 20, right: 20,
          background: "linear-gradient(135deg,#7c3aed,#2563eb)",
          border: "none", color: "#fff", borderRadius: 14,
          padding: "10px 18px", cursor: "pointer",
          fontWeight: 800, fontSize: 13, fontFamily: "'Nunito',sans-serif",
          boxShadow: "0 4px 20px rgba(124,58,237,0.5)",
          animation: "pulse-btn 2.5s infinite",
          display: "flex", alignItems: "center", gap: 8,
        }}
      >
        ⚙️ {isLoggedIn ? "Admin Panel" : "Admin"}
      </button>

      {/* keyboard nav */}
      <KeyboardNav onPrev={prev} onNext={next} />

      {/* REFERENCE PANEL */}
      {showRef && activePage?.reference && (
        <ReferencePanel
          reference={activePage.reference}
          onClose={() => setShowRef(false)}
        />
      )}

      {/* modals */}
      {showLogin && (
        <LoginScreen
          onLogin={() => { setIsLoggedIn(true); setShowLogin(false); setShowAdmin(true); }}
          onClose={() => setShowLogin(false)}
        />
      )}
      {showAdmin && (
        <AdminPanel pages={pages} setPages={setPages} onClose={() => setShowAdmin(false)} />
      )}
    </div>
  );
}
